<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>BEEN Architectural & Engineering | Architects & Construction Services in Kanyakumari</title>
<meta name="description" content="Professional architectural design, 2D plans, 3D elevations, plan approvals, engineering supervision, and construction services in Kanyakumari. Contact BEEN Architectural & Engineering today.">
<link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@400;600;700;900&family=Inter:wght@300;400;500;600&family=Sora:wght@400;600;700;800&family=Manrope:wght@400;500;600;700&display=swap" rel="stylesheet">
<style>
  :root {
    --black: #0D1017;
    --dark: #111318;
    --dark2: #1A1D26;
    --gold: #C9A84C;
    --gold-light: #E8C96A;
    --silver: #A8B2C0;
    --red: #D63031;
    --white: #F0EDE6;
    --white2: #C8C4BC;
    --border: rgba(201,168,76,0.2);
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  html { scroll-behavior: smooth; }

  body {
    font-family: 'Inter', sans-serif;
    background: var(--dark);
    color: var(--white);
    overflow-x: hidden;
  }

  /* BLUEPRINT GRID */
  .blueprint-grid {
    position: absolute;
    inset: 0;
    background-image:
      linear-gradient(rgba(201,168,76,0.06) 1px, transparent 1px),
      linear-gradient(90deg, rgba(201,168,76,0.06) 1px, transparent 1px);
    background-size: 50px 50px;
    pointer-events: none;
  }
  .blueprint-grid::after {
    content: '';
    position: absolute;
    inset: 0;
    background-image:
      linear-gradient(rgba(201,168,76,0.03) 1px, transparent 1px),
      linear-gradient(90deg, rgba(201,168,76,0.03) 1px, transparent 1px);
    background-size: 10px 10px;
  }

  /* NAV */
  nav {
    position: fixed;
    top: 0; left: 0; right: 0;
    z-index: 1000;
    padding: 0 5%;
    height: 70px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: rgba(13,16,23,0.95);
    backdrop-filter: blur(12px);
    border-bottom: 1px solid var(--border);
    transition: all 0.3s;
  }
  .nav-logo {
    display: flex;
    align-items: center;
    gap: 12px;
    text-decoration: none;
  }
  .nav-logo img {
    height: 44px;
    width: 44px;
    object-fit: contain;
    border-radius: 4px;
  }
  .nav-logo-text {
    display: flex;
    flex-direction: column;
  }
  .nav-logo-name {
    font-family: 'Cinzel', serif;
    font-size: 18px;
    font-weight: 700;
    background: linear-gradient(135deg, var(--gold) 0%, var(--silver) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    letter-spacing: 3px;
  }
  .nav-logo-sub {
    font-size: 8px;
    letter-spacing: 2.5px;
    color: var(--silver);
    text-transform: uppercase;
  }
  .nav-links {
    display: flex;
    gap: 18px;
    list-style: none;
  }
  .nav-links a {
    color: var(--silver);
    text-decoration: none;
    font-size: 12px;
    letter-spacing: 2px;
    text-transform: uppercase;
    transition: color 0.3s;
    position: relative;
  }
  .nav-links a::after {
    content: '';
    position: absolute;
    bottom: -4px; left: 0;
    width: 0; height: 1px;
    background: var(--gold);
    transition: width 0.3s;
  }
  .nav-links a:hover { color: var(--gold); }
  .nav-links a:hover::after { width: 100%; }
  .nav-cta {
    background: transparent;
    border: 1px solid var(--gold);
    color: var(--gold) !important;
    padding: 5px 12px;
    border-radius: 2px;
    font-size: 9px !important;
    letter-spacing: 1px !important;
    white-space: nowrap;
    transition: all 0.3s !important;
  }
  .nav-cta:hover {
    background: var(--gold) !important;
    color: var(--black) !important;
  }
  .nav-cta::after { display: none !important; }

  /* LOGIN DROPDOWN */
  .nav-login {
    position: relative;
  }
  .nav-login > .nav-cta {
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 6px;
  }
  .nav-login-caret {
    display: inline-block;
    transition: transform 0.25s;
    font-size: 8px;
  }
  .nav-login.open .nav-login-caret { transform: rotate(180deg); }
  .nav-login-menu {
    position: absolute;
    top: calc(100% + 10px);
    right: 0;
    min-width: 170px;
    background: var(--dark2);
    border: 1px solid var(--border);
    border-radius: 4px;
    box-shadow: 0 12px 28px rgba(0,0,0,0.45);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-6px);
    transition: all 0.2s;
    z-index: 1100;
    overflow: hidden;
  }
  .nav-login.open .nav-login-menu {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
  }
  .nav-login-menu a {
    display: block;
    padding: 11px 16px;
    font-size: 11px;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: var(--white2);
    text-decoration: none;
    border-bottom: 1px solid var(--border);
    transition: background 0.2s, color 0.2s;
  }
  .nav-login-menu a:last-child { border-bottom: none; }
  .nav-login-menu a:hover {
    background: rgba(201,168,76,0.12);
    color: var(--gold);
  }
  @media (max-width: 900px) {
    .nav-login-menu {
      position: static;
      opacity: 1;
      visibility: visible;
      transform: none;
      display: none;
      box-shadow: none;
      margin-top: 8px;
      border: none;
      background: transparent;
    }
    .nav-login.open .nav-login-menu { display: block; }
    .nav-login-menu a { padding: 8px 0; border-bottom: none; }
  }

  /* HERO */
  #home {
    position: relative;
    min-height: 100vh;
    display: flex;
    align-items: center;
    overflow: hidden;
    background: var(--black);
  }
  .hero-bg {
    position: absolute;
    inset: 0;
    background-image: url('data:image/jpeg;base64,');
    background-size: cover;
    background-position: center;
    opacity: 0.18;
  }
  .hero-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(13,16,23,0.97) 0%, rgba(13,16,23,0.7) 50%, rgba(13,16,23,0.95) 100%);
  }
  .hero-content {
    position: relative;
    z-index: 2;
    padding: 140px 8% 100px;
    max-width: 800px;
  }
  .hero-eyebrow {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 32px;
  }
  .hero-eyebrow-line {
    width: 40px;
    height: 1px;
    background: var(--red);
  }
  .hero-eyebrow span {
    font-size: 11px;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--silver);
  }
  .hero-title {
    font-family: 'Cinzel', serif;
    font-size: clamp(36px, 5vw, 68px);
    font-weight: 900;
    line-height: 1.15;
    margin-bottom: 20px;
  }
  .hero-title .gold {
    background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 50%, var(--silver) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .hero-tagline {
    font-family: 'Cinzel', serif;
    font-size: clamp(14px, 1.8vw, 20px);
    color: var(--silver);
    letter-spacing: 2px;
    margin-bottom: 36px;
    font-weight: 400;
    font-style: italic;
  }
  .hero-desc {
    font-size: 15px;
    color: var(--white2);
    line-height: 1.85;
    max-width: 580px;
    margin-bottom: 48px;
    font-weight: 300;
  }
  .hero-btns {
    display: flex;
    flex-wrap: wrap;
    gap: 18px;
    margin-bottom: 68px;
  }
  .btn-primary {
    background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
    color: var(--black);
    border: none;
    padding: 14px 32px;
    font-family: 'Inter', sans-serif;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    cursor: pointer;
    text-decoration: none;
    border-radius: 2px;
    transition: all 0.3s;
    display: inline-block;
  }
  .btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(201,168,76,0.4);
  }
  .btn-outline {
    background: transparent;
    color: var(--white);
    border: 1px solid rgba(168,178,192,0.4);
    padding: 14px 32px;
    font-family: 'Inter', sans-serif;
    font-size: 12px;
    font-weight: 500;
    letter-spacing: 2px;
    text-transform: uppercase;
    cursor: pointer;
    text-decoration: none;
    border-radius: 2px;
    transition: all 0.3s;
    display: inline-block;
  }
  .btn-outline:hover {
    border-color: var(--gold);
    color: var(--gold);
  }
  .btn-wa {
    background: #25D366;
    color: white;
    padding: 14px 32px;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    text-decoration: none;
    border-radius: 2px;
    transition: all 0.3s;
    display: inline-flex;
    align-items: center;
    gap: 8px;
  }
  .btn-wa:hover { background: #1ebe5e; transform: translateY(-2px); }
  .hero-stats {
    display: flex;
    gap: 48px;
    padding-top: 44px;
    border-top: 1px solid var(--border);
  }
  .hero-stat-num {
    font-family: 'Cinzel', serif;
    font-size: 32px;
    font-weight: 700;
    background: linear-gradient(135deg, var(--gold), var(--gold-light));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .hero-stat-label {
    font-size: 11px;
    color: var(--silver);
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-top: 4px;
  }

  /* SECTION BASE */
  section { padding: 100px 8%; }
  .section-eyebrow {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
  }
  .section-eyebrow span {
    font-size: 11px;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--gold);
  }
  .eyebrow-line {
    flex: 1;
    height: 1px;
    background: var(--border);
    max-width: 60px;
  }
  .section-title {
    font-family: 'Cinzel', serif;
    font-size: clamp(28px, 3.5vw, 48px);
    font-weight: 700;
    line-height: 1.2;
    margin-bottom: 16px;
  }
  .section-title .gold {
    background: linear-gradient(135deg, var(--gold), var(--gold-light));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .section-desc {
    font-size: 15px;
    color: var(--white2);
    line-height: 1.8;
    max-width: 560px;
    font-weight: 300;
  }

  /* ABOUT */
  #about {
    background: var(--dark2);
    position: relative;
    overflow: hidden;
  }
  .about-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 80px;
    align-items: center;
    margin-top: 60px;
  }
  .about-img-wrap {
    position: relative;
  }
  .about-img-wrap img {
    width: 100%;
    height: 480px;
    object-fit: cover;
    border-radius: 2px;
  }
  .about-img-badge {
    position: absolute;
    bottom: -24px;
    right: -24px;
    width: 120px;
    height: 120px;
    background: linear-gradient(135deg, var(--gold), var(--gold-light));
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    border-radius: 2px;
  }
  .about-img-badge .num {
    font-family: 'Cinzel', serif;
    font-size: 36px;
    font-weight: 900;
    color: var(--black);
    line-height: 1;
  }
  .about-img-badge .lbl {
    font-size: 9px;
    font-weight: 700;
    color: var(--black);
    letter-spacing: 1.5px;
    text-transform: uppercase;
    text-align: center;
    margin-top: 4px;
  }
  .about-content { padding-left: 20px; }
  .about-content .section-desc { margin-bottom: 28px; }
  .about-highlights {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
    margin-top: 32px;
  }
  .about-highlight-item {
    display: flex;
    align-items: flex-start;
    gap: 10px;
  }
  .about-highlight-dot {
    width: 6px;
    height: 6px;
    background: var(--red);
    border-radius: 50%;
    margin-top: 6px;
    flex-shrink: 0;
  }
  .about-highlight-item span {
    font-size: 13px;
    color: var(--white2);
    letter-spacing: 0.5px;
  }

  /* SERVICES */
  #services {
    position: relative;
    overflow: hidden;
    background: var(--black);
  }
  .services-header { margin-bottom: 60px; }
  .services-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 2px;
  }
  .service-card {
    background: var(--dark2);
    padding: 40px 28px;
    border-top: 2px solid transparent;
    transition: all 0.4s;
    position: relative;
    overflow: hidden;
  }
  .service-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, var(--gold), var(--red));
    transform: scaleX(0);
    transform-origin: left;
    transition: transform 0.4s;
  }
  .service-card:hover::before { transform: scaleX(1); }
  .service-card:hover { background: #1e222e; }
  .service-icon {
    font-size: 36px;
    margin-bottom: 20px;
    display: block;
  }
  .service-card h3 {
    font-family: 'Cinzel', serif;
    font-size: 16px;
    font-weight: 600;
    color: var(--gold);
    margin-bottom: 16px;
    letter-spacing: 1px;
  }
  .service-card ul {
    list-style: none;
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .service-card ul li {
    font-size: 13px;
    color: var(--white2);
    padding-left: 14px;
    position: relative;
    line-height: 1.5;
  }
  .service-card ul li::before {
    content: '—';
    position: absolute;
    left: 0;
    color: var(--red);
    font-size: 10px;
  }

  /* WHY CHOOSE */
  #why {
    background: var(--dark2);
    position: relative;
  }
  .why-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 32px;
    margin-top: 60px;
  }
  .why-card {
    padding: 36px 28px;
    border: 1px solid var(--border);
    border-radius: 2px;
    transition: all 0.4s;
    position: relative;
  }
  .why-card:hover {
    border-color: var(--gold);
    transform: translateY(-4px);
    box-shadow: 0 20px 40px rgba(0,0,0,0.4);
  }
  .why-number {
    font-family: 'Cinzel', serif;
    font-size: 48px;
    font-weight: 900;
    color: rgba(201,168,76,0.1);
    position: absolute;
    top: 20px;
    right: 24px;
    line-height: 1;
  }
  .why-card h3 {
    font-family: 'Cinzel', serif;
    font-size: 17px;
    font-weight: 600;
    color: var(--white);
    margin-bottom: 12px;
    margin-top: 8px;
  }
  .why-card p {
    font-size: 14px;
    color: var(--white2);
    line-height: 1.7;
    font-weight: 300;
  }
  .why-icon {
    font-size: 28px;
    margin-bottom: 12px;
    display: block;
  }

  /* PROCESS */
  #process {
    background: var(--black);
    overflow: hidden;
  }
  .process-steps {
    display: flex;
    gap: 0;
    margin-top: 60px;
    position: relative;
  }
  .process-steps::before {
    content: '';
    position: absolute;
    top: 32px;
    left: 32px;
    right: 32px;
    height: 1px;
    background: linear-gradient(90deg, var(--gold), var(--silver), var(--gold));
    opacity: 0.3;
  }
  .process-step {
    flex: 1;
    text-align: center;
    padding: 0 20px;
    position: relative;
  }
  .process-num {
    width: 64px;
    height: 64px;
    background: var(--dark2);
    border: 1px solid var(--gold);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 24px;
    font-family: 'Cinzel', serif;
    font-size: 18px;
    font-weight: 700;
    color: var(--gold);
    position: relative;
    z-index: 1;
  }
  .process-step h3 {
    font-family: 'Cinzel', serif;
    font-size: 15px;
    font-weight: 600;
    color: var(--white);
    margin-bottom: 10px;
  }
  .process-step p {
    font-size: 13px;
    color: var(--white2);
    line-height: 1.6;
    font-weight: 300;
  }

  /* PORTFOLIO */
  #portfolio {
    background: var(--dark2);
  }
  .portfolio-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2px;
    margin-top: 60px;
  }
  .portfolio-item {
    position: relative;
    overflow: hidden;
    aspect-ratio: 4/3;
    cursor: pointer;
  }
  .portfolio-item img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.6s ease;
  }
  .portfolio-item:hover img { transform: scale(1.08); }
  .portfolio-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(to top, rgba(13,16,23,0.9) 0%, transparent 60%);
    opacity: 0;
    transition: opacity 0.4s;
    display: flex;
    align-items: flex-end;
    padding: 24px;
  }
  .portfolio-item:hover .portfolio-overlay { opacity: 1; }
  .portfolio-overlay h3 {
    font-family: 'Cinzel', serif;
    font-size: 16px;
    color: var(--white);
    margin-bottom: 6px;
  }
  .portfolio-overlay p {
    font-size: 12px;
    color: var(--gold);
    letter-spacing: 1.5px;
    text-transform: uppercase;
  }

  /* CONTACT */
  #contact {
    background: var(--black);
    position: relative;
    overflow: hidden;
  }
  .contact-grid {
    display: grid;
    grid-template-columns: 1fr 1.4fr;
    gap: 80px;
    margin-top: 60px;
    align-items: start;
  }
  .contact-info h3 {
    font-family: 'Cinzel', serif;
    font-size: 22px;
    color: var(--gold);
    margin-bottom: 12px;
  }
  .contact-info p {
    font-size: 14px;
    color: var(--white2);
    line-height: 1.8;
    margin-bottom: 36px;
    font-weight: 300;
  }
  .contact-detail {
    display: flex;
    align-items: flex-start;
    gap: 16px;
    margin-bottom: 24px;
  }
  .contact-icon {
    width: 44px;
    height: 44px;
    border: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    flex-shrink: 0;
    border-radius: 2px;
  }
  .contact-detail-text .label {
    font-size: 10px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--gold);
    margin-bottom: 4px;
  }
  .contact-detail-text a,
  .contact-detail-text span {
    font-size: 14px;
    color: var(--white);
    text-decoration: none;
    transition: color 0.3s;
    display: block;
    line-height: 1.5;
  }
  .contact-detail-text a:hover { color: var(--gold); }
  .contact-form {
    display: flex;
    flex-direction: column;
    gap: 18px;
  }
  .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 18px; }
  .form-group { display: flex; flex-direction: column; gap: 8px; }
  .form-group label {
    font-size: 11px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--silver);
  }
  .form-group input,
  .form-group select,
  .form-group textarea {
    background: var(--dark2);
    border: 1px solid rgba(168,178,192,0.15);
    border-radius: 2px;
    padding: 12px 16px;
    color: var(--white);
    font-family: 'Inter', sans-serif;
    font-size: 14px;
    outline: none;
    transition: border-color 0.3s;
    width: 100%;
  }
  .form-group input:focus,
  .form-group select:focus,
  .form-group textarea:focus { border-color: var(--gold); }
  .form-group select option { background: var(--dark2); }
  .form-group textarea { resize: vertical; min-height: 120px; }
  .form-submit {
    background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
    color: var(--black);
    border: none;
    padding: 16px 40px;
    font-family: 'Inter', sans-serif;
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 2.5px;
    text-transform: uppercase;
    cursor: pointer;
    border-radius: 2px;
    transition: all 0.3s;
    align-self: flex-start;
  }
  .form-submit:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(201,168,76,0.4);
  }

  /* FOOTER */
  footer {
    background: var(--black);
    border-top: 1px solid var(--border);
    padding: 60px 8% 30px;
  }
  .footer-grid {
    display: grid;
    grid-template-columns: 1.5fr 1fr 1fr 1fr;
    gap: 60px;
    padding-bottom: 48px;
    border-bottom: 1px solid var(--border);
  }
  .footer-brand img {
    height: 60px;
    margin-bottom: 16px;
  }
