  const closeBtn = document.getElementById('cpClose');
  const tabs = panel ? Array.from(panel.querySelectorAll('[data-cp-tab]')) : [];
  const forms = panel ? Array.from(panel.querySelectorAll('[data-cp-form]')) : [];
  if (!panel || !toggle) return;
  let collapsed = false;
  let userClosed = false;

  function setActiveTab(name) {
    tabs.forEach((tab) => {
      const active = tab.dataset.cpTab === name;
      tab.classList.toggle('active', active);
      tab.setAttribute('aria-selected', String(active));
    });
    forms.forEach((form) => {
      const active = form.dataset.cpForm === name;
      form.classList.toggle('active', active);
      form.style.display = active ? 'flex' : 'none';
    });
  }

  tabs.forEach((tab) => {
    tab.addEventListener('click', (e) => {
      e.stopPropagation();
      setActiveTab(tab.dataset.cpTab);
    });
  });

  // ── Custom file upload fields (e.g. resume) — echo filename, show focus/selected state ──
  panel.querySelectorAll('.cp-file input[type="file"]').forEach((input) => {
    const wrap = input.closest('.cp-file');
    const textEl = wrap.querySelector('.cp-file-text');
    const defaultText = textEl.textContent;
    input.addEventListener('change', () => {
      const file = input.files && input.files[0];
      if (file) {
        const sizeMB = file.size / (1024 * 1024);
        if (sizeMB > 5) {
          textEl.textContent = 'File too large — max 5MB';
          wrap.classList.remove('cp-file-has');
          input.value = '';
          return;
        }
        textEl.textContent = file.name;
        wrap.classList.add('cp-file-has');
      } else {
        textEl.textContent = defaultText;
        wrap.classList.remove('cp-file-has');
      }
    });
    input.addEventListener('focus', () => wrap.classList.add('cp-file-focus'));
    input.addEventListener('blur', () => wrap.classList.remove('cp-file-focus'));
  });

  function expandFullscreen() {
    collapsed = false;
    userClosed = false;
    panel.classList.remove('collapsed');
    panel.classList.add('cp-fullscreen');
  }

  function closeFullscreen(toCollapsed) {
    panel.classList.remove('cp-fullscreen');
    if (toCollapsed) {
      collapsed = true;
      userClosed = true;
      panel.classList.add('collapsed');
    }
  }

  // The pull-tab ONLY hides/unhides the docked drawer — it never triggers fullscreen.
  // This is the only action that can bring the drawer back once the user has closed it.
  toggle.addEventListener('click', (e) => {
    e.stopPropagation();
    if (panel.classList.contains('cp-fullscreen')) return;
    collapsed = !collapsed;
    userClosed = collapsed;
    panel.classList.toggle('collapsed', collapsed);
  });

  // Clicking anywhere inside the open drawer body (not the pull-tab, not close)
  // expands it to cover the hero section fully.
  panel.addEventListener('click', (e) => {
    if (e.target.closest('#cpClose')) return;
    if (e.target.closest('#cpToggle')) return;
    if (panel.classList.contains('cp-fullscreen')) return;
    if (panel.classList.contains('collapsed')) return;
    expandFullscreen();
  });

  if (closeBtn) {
    closeBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      closeFullscreen(true);
    });
  }

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && panel.classList.contains('cp-fullscreen')) {
      closeFullscreen(true);
    }
  });

  // Auto-collapse when scrolled past hero. It will still tuck itself away when
  // scrolled out of the hero, but it will only auto-reopen on scroll-back if the
  // user hasn't deliberately closed it — once closed, only the pull-tab reopens it.
  window.addEventListener('scroll', () => {
    const hero = document.getElementById('home');
    if (!hero) return;
    const rect = hero.getBoundingClientRect();
    if (rect.bottom < 0 && !collapsed) {
      collapsed = true;
      panel.classList.add('collapsed');
      panel.classList.remove('cp-fullscreen');
    } else if (rect.bottom >= 0 && collapsed && !userClosed) {
      collapsed = false;
      panel.classList.remove('collapsed');
    }
  });

  setActiveTab('jobseeker');

  // Auto-open the panel (fullscreen, Employer tab) when arriving via a
  // direct link such as index.php#consultancy-panel-employer
  if (window.location.hash === '#consultancy-panel-employer') {
    const employerTab = tabs.find((tab) => tab.dataset.cpTab === 'employer');
    if (employerTab) employerTab.click();
    expandFullscreen();
    panel.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
})();

// CONSULTANCY FORM SUBMIT
// ── HTML5 NATIVE BROWSER VALIDATION (white tooltip popups) ──
// All 7 rules: Name, Email, Phone, Role, Location, Availability, Portfolio, Skills/Notes

const cpRules = {
  // 1. Name — letters & spaces only
  'js-name':        { pattern: /^[A-Za-z ]{2,60}$/,                                          msg: 'Enter a valid full name (letters only).' },
  'em-contact':     { pattern: /^[A-Za-z ]{2,60}$/,                                          msg: 'Enter a valid full name (letters only).' },

  // 2. Email — strictly lowercase, start with letter, valid format
  'js-email':       { pattern: /^[a-z][a-z0-9._+\-]*@[a-z0-9.\-]+\.[a-z]{2,}$/,            msg: 'Email must be in lowercase, start with a letter, and be in a valid format.' },
  'em-email':       { pattern: /^[a-z][a-z0-9._+\-]*@[a-z0-9.\-]+\.[a-z]{2,}$/,            msg: 'Email must be in lowercase, start with a letter, and be in a valid format.' },

  // 3. Phone — exactly 10 digits
  'js-phone':       { pattern: /^[0-9]{10}$/,                                                msg: 'Please enter a valid 10-digit phone number.' },
  'em-phone':       { pattern: /^[0-9]{10}$/,                                                msg: 'Please enter a valid 10-digit phone number.' },

  // 4. Role & Location — letters and spaces only
  'js-role':        { pattern: /^[A-Za-z ]{2,}$/,                                            msg: 'Only letters and spaces are allowed.' },
  'em-role':        { pattern: /^[A-Za-z ]{2,}$/,                                            msg: 'Only letters and spaces are allowed.' },
  'js-location':    { pattern: /^[A-Za-z ]{2,}$/,                                            msg: 'Only letters and spaces are allowed.' },
  'em-location':    { pattern: /^[A-Za-z ]{2,}$/,                                            msg: 'Only letters and spaces are allowed.' },
  'em-name':        { pattern: /^.{2,}$/,                                                    msg: 'Please enter your company name.' },

  // 5. Available From — "Immediate" OR date (YYYY-MM-DD)
  'js-availability':{ pattern: /^(Immediate|immediate|IMMEDIATE|\d{4}-\d{2}-\d{2})$/,        msg: "Please enter 'Immediate' or select a valid date (YYYY-MM-DD)." },

  // 6. Portfolio — must start with http:// or https://
  'js-portfolio':   { pattern: /^https?:\/\/.+/,                                             msg: 'Please enter a valid URL/link format (must start with http:// or https://).' },

  // 7. Skills & Notes — letters, spaces, commas, periods only
  'js-notes':       { pattern: /^[A-Za-z ,.]{0,}$/,                                         msg: 'Only letters, spaces, commas, and periods are allowed.' },
  'em-notes':       { pattern: /^[\s\S]{0,}$/,                                              msg: '' },
};

function cpSetValidity(field) {
  const rule = cpRules[field.id];
  const val  = field.value.trim();

  // File fields — handled separately
  if (field.type === 'file') return;

  if (!rule) { field.setCustomValidity(''); return; }

  if (field.required && !val) {
    field.setCustomValidity('This field is required.');
  } else if (val && !rule.pattern.test(val)) {
    field.setCustomValidity(rule.msg);
  } else {
    field.setCustomValidity('');
  }
}

// Attach events to all ruled fields
Object.keys(cpRules).forEach(id => {
  const el = document.getElementById(id);
  if (!el) return;
  el.addEventListener('input',  () => cpSetValidity(el));
  el.addEventListener('blur',   () => { cpSetValidity(el); });
  el.addEventListener('change', () => cpSetValidity(el));
});

// ── Availability field: toggle between text & date ──
(function() {
  const avail = document.getElementById('js-availability');
  if (!avail) return;

