    <button type="button" id="avail-date-btn" style="font-size:10px;padding:3px 8px;border-radius:4px;border:1px solid rgba(34,211,102,0.4);background:rgba(34,211,102,0.1);color:#86EFAC;cursor:pointer;font-family:Manrope,sans-serif;">📅 Pick Date</button>
  `;
  wrapper.appendChild(hint);

  document.getElementById('avail-text-btn').addEventListener('click', () => {
    avail.type = 'text';
    avail.placeholder = 'Immediate';
    avail.value = '';
    avail.setCustomValidity('');
  });
  document.getElementById('avail-date-btn').addEventListener('click', () => {
    avail.type = 'date';
    avail.value = '';
    avail.setCustomValidity('');
    // When date is picked, store in YYYY-MM-DD — always valid
    avail.addEventListener('change', () => avail.setCustomValidity(''), { once: false });
  });
})();

// ── File (Resume) validation ──
(function() {
  const resume = document.getElementById('js-resume');
  if (!resume) return;
  resume.addEventListener('change', () => {
    if (!resume.files || !resume.files[0]) {
      resume.setCustomValidity('Please upload your resume.');
      return;
    }
    const allowed = [
      'application/pdf',
      'application/msword',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
    ];
    resume.setCustomValidity(
      allowed.includes(resume.files[0].type) ? '' : 'Only PDF or DOC/DOCX files are allowed.'
    );
  });
})();

