function cpSubmit(e, type) {
  e.preventDefault();
  const form = e.target;

  // Run setCustomValidity on all tracked fields before checking
  form.querySelectorAll('input, select, textarea').forEach(f => cpSetValidity(f));

  // Native HTML5 browser tooltip validation
  if (!form.checkValidity()) {
    form.reportValidity();
    return;
  }

  const btn = form.querySelector('.cp-btn');
  const btnText = btn.querySelector('.cp-btn-text');
  const roleLabel = type === 'employer' ? 'Employer' : 'Jobseeker';
  btnText.textContent = 'Submitting...';
  btn.disabled = true;

  function showSuccess() {
    form.style.display = 'none';
    const success = document.createElement('div');
    success.style.cssText = 'text-align:center;padding:20px 0;';
    success.innerHTML = `
      <div style="width:56px;height:56px;background:linear-gradient(135deg,#8B5CF6,#22D3EE);border:none;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 14px;font-size:24px;color:#100A20;box-shadow:0 8px 24px rgba(139,92,246,0.4);">✓</div>
      <h4 style="font-family:Sora,sans-serif;font-size:16px;font-weight:700;color:#F3F1FA;margin-bottom:8px;">${roleLabel} Registration Received!</h4>
      <p style="font-family:Manrope,sans-serif;font-size:12px;color:rgba(202,196,224,0.65);line-height:1.6;">We will contact you within 24 hours to continue the job consultancy process.</p>
      ${type === 'employer' ? `
      ` : ''}
      <a href="https://wa.me/918300890938" target="_blank" style="display:inline-flex;align-items:center;gap:6px;margin-top:14px;color:#25D366;font-family:Manrope,sans-serif;font-size:11px;font-weight:600;text-decoration:none;border:1px solid rgba(37,211,102,0.3);padding:8px 16px;border-radius:999px;">
        <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
        WhatsApp Now
      </a>`;
    form.parentElement.insertBefore(success, form);

    if (type === 'employer') {
      // Payment disabled — no-op
    }
  }

  if (type === 'jobseeker' || type === 'employer') {
    // Real submission to backend
    const formData = new FormData(form);
    const endpoint = type === 'jobseeker' ? 'api/jobseeker.php' : 'api/employer.php';
    fetch(endpoint, {
      method: 'POST',
      body: formData
    })
    .then(res => res.json())
    .then(data => {
      if (data.success) {
        showSuccess();
      } else {
        btnText.textContent = roleLabel === 'Employer' ? 'Register as Employer' : 'Register as Jobseeker';
        btn.disabled = false;
        alert(data.error || 'Something went wrong. Please try again.');
      }
    })
    .catch(err => {
      console.error(err);
      btnText.textContent = roleLabel === 'Employer' ? 'Register as Employer' : 'Register as Jobseeker';
      btn.disabled = false;
      alert('Could not submit. Please check your connection and try again.');
    });
  } else {
    setTimeout(showSuccess, 1200);
  }
}


