// COUNTER ANIMATION
function animateCounters() {
  document.querySelectorAll('[data-count]').forEach(el => {
    const target = parseInt(el.getAttribute('data-count'));
    let current = 0;
    const step = target / 60;
    const timer = setInterval(() => {
      current += step;
      if (current >= target) {
        el.textContent = target + '+';
        clearInterval(timer);
      } else {
        el.textContent = Math.floor(current) + '+';
      }
    }, 20);
  });
}

// SCROLL REVEAL
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
    }
  });
}, { threshold: 0.1 });

document.querySelectorAll('.reveal').forEach(el => observer.observe(el));

// STICKY NAV
window.addEventListener('scroll', () => {
  const nav = document.getElementById('navbar');
  if (window.scrollY > 50) {
    nav.style.background = 'rgba(13,16,23,0.98)';
    nav.style.boxShadow = '0 4px 30px rgba(0,0,0,0.5)';
  } else {
    nav.style.background = 'rgba(13,16,23,0.95)';
    nav.style.boxShadow = 'none';
  }
});

// START COUNTERS WHEN HERO IS IN VIEW
const heroObserver = new IntersectionObserver((entries) => {
  if (entries[0].isIntersecting) {
    setTimeout(animateCounters, 800);
    heroObserver.disconnect();
  }
}, { threshold: 0.3 });
heroObserver.observe(document.getElementById('home'));

// FORM SUBMIT
function handleForm(e) {
  e.preventDefault();
  const form = e.target;
  const btn = form.querySelector('.form-submit');
  btn.textContent = 'Sending...';
  btn.disabled = true;

  const formData = new FormData(form);

  fetch('api/client_inquiry.php', {
    method: 'POST',
    body: formData
  })
  .then(res => res.json())
  .then(data => {
    if (data.success) {
      btn.textContent = '✓ Message Sent!';
      btn.style.background = '#25D366';
      form.reset();
      setTimeout(() => {
        btn.textContent = 'Get Free Consultation';
        btn.style.background = '';
        btn.disabled = false;
      }, 4000);
    } else {
      btn.textContent = 'Get Free Consultation';
      btn.disabled = false;
      alert(data.error || 'Something went wrong. Please try again.');
    }
  })
  .catch(err => {
    console.error(err);
    btn.textContent = 'Get Free Consultation';
    btn.disabled = false;
    alert('Could not submit. Please check your connection and try again.');
  });
}
</script>

<!-- THREE.JS 3D HERO BACKGROUND -->
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script>
(function() {
  const canvas = document.getElementById('heroCanvas');
  if (!canvas) return;

  const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x000000, 0);

  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(60, canvas.clientWidth / canvas.clientHeight, 0.1, 1000);
  camera.position.set(0, 0, 30);

  function resize() {
    const hero = document.getElementById('home');
    const w = hero.clientWidth, h = hero.clientHeight;
    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
  }
  resize();
  window.addEventListener('resize', resize);

  // COLORS
  const GOLD = new THREE.Color(0xC9A84C);
  const SILVER = new THREE.Color(0xA8B2C0);
  const RED = new THREE.Color(0xD63031);
  const WHITE = new THREE.Color(0xF0EDE6);

  // ── 1. FLOATING PARTICLES (gold dust) ──
  const particleCount = 280;
  const positions = new Float32Array(particleCount * 3);
  const colors = new Float32Array(particleCount * 3);
  const sizes = new Float32Array(particleCount);
  for (let i = 0; i < particleCount; i++) {
    positions[i*3]   = (Math.random() - 0.5) * 100;
    positions[i*3+1] = (Math.random() - 0.5) * 60;
    positions[i*3+2] = (Math.random() - 0.5) * 40;
    const c = Math.random() < 0.6 ? GOLD : (Math.random() < 0.7 ? SILVER : WHITE);
    colors[i*3] = c.r; colors[i*3+1] = c.g; colors[i*3+2] = c.b;
    sizes[i] = Math.random() * 2.5 + 0.5;
  }
  const pGeo = new THREE.BufferGeometry();
  pGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  pGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  pGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

  const pMat = new THREE.PointsMaterial({
    size: 0.35,
    vertexColors: true,
    transparent: true,
    opacity: 0.65,
    sizeAttenuation: true,
    blending: THREE.AdditiveBlending,
    depthWrite: false
  });
  const particles = new THREE.Points(pGeo, pMat);
  scene.add(particles);

  // ── 2. WIREFRAME BUILDING STRUCTURES ──
  function makeBuildingWireframe(w, h, d, color, opacity) {
    const geo = new THREE.BoxGeometry(w, h, d);
    const mat = new THREE.MeshBasicMaterial({
      color,
      wireframe: true,
      transparent: true,
      opacity,
      blending: THREE.AdditiveBlending,
      depthWrite: false
    });
    return new THREE.Mesh(geo, mat);
  }

  // Main tall building (center-right)
  const b1 = makeBuildingWireframe(3, 14, 3, GOLD, 0.18);
  b1.position.set(14, -2, -8);
  scene.add(b1);

  // Shorter building
  const b2 = makeBuildingWireframe(4, 9, 4, SILVER, 0.12);
  b2.position.set(18, -5, -12);
  scene.add(b2);

  // Far background tall tower
  const b3 = makeBuildingWireframe(2, 18, 2, GOLD, 0.09);
  b3.position.set(-16, -1, -15);
  scene.add(b3);

  // Wide low building
  const b4 = makeBuildingWireframe(8, 5, 3, SILVER, 0.08);
  b4.position.set(-12, -7, -10);
  scene.add(b4);

  // Small accent cube
  const b5 = makeBuildingWireframe(2, 2, 2, RED, 0.2);
  b5.position.set(20, 5, -5);
  scene.add(b5);

  // ── 3. FLOATING GRID PLANES (blueprint feel) ──
  function makeGridPlane(size, divs, color, opacity, rx, ry, rz, pos) {
    const geo = new THREE.PlaneGeometry(size, size, divs, divs);
    const mat = new THREE.MeshBasicMaterial({
      color,
      wireframe: true,
      transparent: true,
      opacity,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      side: THREE.DoubleSide
    });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.rotation.set(rx, ry, rz);
    mesh.position.set(...pos);
    return mesh;
  }

  const grid1 = makeGridPlane(30, 10, GOLD, 0.06, -Math.PI/2, 0, 0, [0, -12, -5]);
  scene.add(grid1);

  const grid2 = makeGridPlane(20, 8, SILVER, 0.04, 0, Math.PI/6, 0, [-20, 0, -18]);
  scene.add(grid2);

  // ── 4. ORBITING RINGS (architectural compass arcs) ──
  function makeArc(radius, color, opacity) {
    const curve = new THREE.EllipseCurve(0, 0, radius, radius, 0, Math.PI * 1.5, false, 0);
    const pts = curve.getPoints(80);
    const geo = new THREE.BufferGeometry().setFromPoints(pts.map(p => new THREE.Vector3(p.x, p.y, 0)));
    const mat = new THREE.LineBasicMaterial({ color, transparent: true, opacity, blending: THREE.AdditiveBlending });
    return new THREE.Line(geo, mat);
  }

  const ring1 = makeArc(12, GOLD, 0.15);
  ring1.position.set(10, 3, -10);
  ring1.rotation.x = 0.3;
  scene.add(ring1);

  const ring2 = makeArc(7, SILVER, 0.1);
  ring2.position.set(-8, 2, -8);
  ring2.rotation.y = 0.5;
  scene.add(ring2);

  // ── 5. DIAGONAL LINES (like the red arrow in logo) ──
  function makeLine(from, to, color, opacity) {
    const geo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(...from), new THREE.Vector3(...to)
    ]);
    const mat = new THREE.LineBasicMaterial({ color, transparent: true, opacity, blending: THREE.AdditiveBlending });
    return new THREE.Line(geo, mat);
  }

  for (let i = 0; i < 8; i++) {
    const x = (Math.random() - 0.5) * 60;
    const y = (Math.random() - 0.5) * 40;
    const z = -10 - Math.random() * 15;
    const len = 5 + Math.random() * 10;
    const col = Math.random() < 0.3 ? RED : (Math.random() < 0.6 ? GOLD : SILVER);
    const line = makeLine([x, y, z], [x + len, y + len * 0.6, z], col, 0.12 + Math.random() * 0.1);
    scene.add(line);
  }

  // ── MOUSE PARALLAX ──
  let mouseX = 0, mouseY = 0;
  let targetX = 0, targetY = 0;
  document.addEventListener('mousemove', e => {
    mouseX = (e.clientX / window.innerWidth - 0.5) * 2;
    mouseY = (e.clientY / window.innerHeight - 0.5) * 2;
  });

  // ── ANIMATION LOOP ──
  let t = 0;
  function animate() {
    requestAnimationFrame(animate);
    t += 0.004;

    // Smooth mouse follow
    targetX += (mouseX - targetX) * 0.03;
    targetY += (mouseY - targetY) * 0.03;
    camera.position.x = targetX * 3;
    camera.position.y = -targetY * 2;
    camera.lookAt(0, 0, 0);

    // Rotate particles slowly
    particles.rotation.y = t * 0.06;
    particles.rotation.x = t * 0.02;

    // Breathe buildings
    b1.rotation.y = t * 0.15;
    b2.rotation.y = -t * 0.1;
    b3.rotation.y = t * 0.08;
    b5.rotation.x = t * 0.4;
    b5.rotation.y = t * 0.3;

    // Float grids
    grid1.position.y = -12 + Math.sin(t * 0.5) * 0.5;
    grid2.rotation.y += 0.002;

    // Spin rings
    ring1.rotation.z = t * 0.2;
    ring2.rotation.z = -t * 0.15;

    // Pulse particle opacity
    pMat.opacity = 0.5 + Math.sin(t * 0.8) * 0.15;

    renderer.render(scene, camera);
  }
  animate();
})();
</script>

