  color: var(--cp-text-dim);
  letter-spacing: 0.5px;
  text-transform: uppercase;
  margin-top: 3px;
  font-weight: 600;
}
.cp-toggle {
  position: absolute;
  left: -46px;
  top: 50%;
  transform: translateY(-50%);
  width: 46px;
  height: 150px;
  background: linear-gradient(160deg, #1B1233, #0E0B1F);
  border: 1px solid var(--cp-border);
  border-right: none;
  border-radius: 999px 0 0 999px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  cursor: pointer;
  color: var(--cp-cyan);
  transition: background 0.3s, border-color 0.3s, box-shadow 0.3s;
  backdrop-filter: blur(12px);
  z-index: 5;
  padding: 16px 0;
  box-shadow: -10px 0 26px rgba(0,0,0,0.45);
}
.cp-toggle::before {
  content: '';
  position: absolute;
  inset: 3px 3px 3px 10px;
  border-radius: 999px 0 0 999px;
  background: var(--cp-grad);
  opacity: 0.12;
  transition: opacity 0.3s;
}
.cp-toggle:hover {
  border-color: var(--cp-border-focus);
  box-shadow: -10px 0 30px rgba(139,92,246,0.3);
}
.cp-toggle:hover::before { opacity: 0.22; }
.cp-toggle svg { transition: transform 0.4s ease; flex-shrink: 0; position: relative; z-index: 1; }
.cp-toggle-label {
  writing-mode: vertical-rl;
  text-orientation: mixed;
  font-family: 'Sora', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  color: var(--cp-text);
  white-space: nowrap;
  position: relative;
  z-index: 1;
}
#consultancy-panel.collapsed .cp-toggle svg { transform: rotate(180deg); }
/* Mobile — same full-height right-edge panel as desktop, just narrower */
@media (max-width: 900px) {
  #consultancy-panel {
    width: min(86vw, 360px);
  }
  .cp-field-row { grid-template-columns: 1fr; }
  .cp-trust { grid-template-columns: 1fr 1fr 1fr; }
}
</style>

<!-- SCROLL PROGRESS BAR -->
<div id="scroll-progress"></div>

<!-- CURSOR -->
<div class="cursor-dot" id="cursorDot"></div>
<div class="cursor-ring" id="cursorRing"></div>

<!-- FLOATING BACKGROUND PARTICLES (whole page) -->
<div id="page-particles"></div>

<!-- SECTION CANVASES for about / services / why / contact -->
<canvas id="aboutCanvas"   class="section-canvas" style="position:absolute;top:0;left:0;width:100%;height:100%;"></canvas>

<script>
// ── SCROLL PROGRESS ──
window.addEventListener('scroll', () => {
  const prog = document.getElementById('scroll-progress');
  const total = document.body.scrollHeight - window.innerHeight;
  prog.style.width = (window.scrollY / total * 100) + '%';
});

// ── CUSTOM CURSOR ──
const dot = document.getElementById('cursorDot');
const ring = document.getElementById('cursorRing');
let cx = 0, cy = 0, rx = 0, ry = 0;
document.addEventListener('mousemove', e => { cx = e.clientX; cy = e.clientY; });
function moveCursor() {
  dot.style.left = cx + 'px'; dot.style.top = cy + 'px';
  rx += (cx - rx) * 0.12; ry += (cy - ry) * 0.12;
  ring.style.left = rx + 'px'; ring.style.top = ry + 'px';
  requestAnimationFrame(moveCursor);
}
moveCursor();
// Expand ring on interactive elements
document.querySelectorAll('a, button, .service-card, .why-card, .portfolio-item').forEach(el => {
  el.addEventListener('mouseenter', () => {
    ring.style.width = '60px'; ring.style.height = '60px';
    ring.style.borderColor = 'rgba(201,168,76,0.8)';
    dot.style.transform = 'translate(-50%,-50%) scale(1.5)';
  });
  el.addEventListener('mouseleave', () => {
    ring.style.width = '36px'; ring.style.height = '36px';
    ring.style.borderColor = 'rgba(201,168,76,0.5)';
    dot.style.transform = 'translate(-50%,-50%) scale(1)';
  });
});

// ── FLOATING PAGE PARTICLES ──
const ppContainer = document.getElementById('page-particles');
const ppColors = ['#C9A84C','#A8B2C0','#D63031','#E8C96A','#F0EDE6'];
for (let i = 0; i < 50; i++) {
  const p = document.createElement('div');
  p.className = 'fp';
  const size = Math.random() * 4 + 1;
  const col = ppColors[Math.floor(Math.random() * ppColors.length)];
  const duration = 12 + Math.random() * 20;
  const delay = Math.random() * 20;
  p.style.cssText = `
    width:${size}px; height:${size}px;
    background:${col};
    left:${Math.random()*100}%;
    top:${Math.random()*100}%;
    animation-duration:${duration}s;
    animation-delay:-${delay}s;
    box-shadow: 0 0 ${size*3}px ${col};
    opacity:0.4;
  `;
  ppContainer.appendChild(p);
}

// ── TYPING EFFECT on hero tagline ──
const tagline = document.querySelector('.hero-tagline');
if (tagline) {
  const text = tagline.textContent;
  tagline.textContent = '';
  tagline.classList.add('typing-text');
  let i = 0;
  function typeNext() {
    if (i < text.length) {
      tagline.textContent = text.slice(0, ++i);
      setTimeout(typeNext, 45 + Math.random() * 30);
    } else {
      tagline.classList.remove('typing-text');
    }
  }
  setTimeout(typeNext, 1200);
}

// ── GLOWING DIVIDERS between sections ──
document.querySelectorAll('section').forEach((sec, i) => {
  if (i > 0) {
    const div = document.createElement('div');
    div.className = 'glow-divider';
    sec.parentNode.insertBefore(div, sec);
  }
});

// ── ABOUT SECTION: Three.js floating geometric shapes ──
(function() {
  const aboutSec = document.getElementById('about');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  aboutSec.style.position = 'relative';
  aboutSec.insertBefore(canvas, aboutSec.firstChild);

  const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
  renderer.setClearColor(0, 0);
  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(60, 2, 0.1, 100);
  camera.position.z = 20;

  function resize() {
    const w = aboutSec.clientWidth, h = aboutSec.clientHeight;
    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
  }
  resize();
  window.addEventListener('resize', resize);

  // Floating torus knots
  const shapes = [];
  const mats = [
    new THREE.MeshBasicMaterial({ color: 0xC9A84C, wireframe: true, transparent: true, opacity: 0.08 }),
    new THREE.MeshBasicMaterial({ color: 0xA8B2C0, wireframe: true, transparent: true, opacity: 0.06 }),
    new THREE.MeshBasicMaterial({ color: 0xD63031, wireframe: true, transparent: true, opacity: 0.05 }),
  ];
  [[new THREE.TorusKnotGeometry(3, 0.8, 80, 12), 0, -14, -8, 0],
   [new THREE.OctahedronGeometry(4), -18, 4, -10, 1],
   [new THREE.IcosahedronGeometry(3), 16, 6, -6, 2],
   [new THREE.TorusGeometry(5, 0.3, 12, 40), 20, -8, -12, 1],
   [new THREE.DodecahedronGeometry(2.5), -20, -6, -8, 0],
  ].forEach(([geo, x, y, z, mi]) => {
    const m = new THREE.Mesh(geo, mats[mi]);
    m.position.set(x, y, z);
    scene.add(m);
    shapes.push(m);
  });

  let t = 0;
  function loop() {
    requestAnimationFrame(loop);
    t += 0.005;
    shapes.forEach((s, i) => {
      s.rotation.x += 0.003 + i * 0.001;
      s.rotation.y += 0.004 + i * 0.001;
      s.position.y += Math.sin(t + i) * 0.008;
    });
    renderer.render(scene, camera);
  }
  loop();
})();

// ── SERVICES SECTION: Canvas dot-grid that reacts to scroll ──
(function() {
  const sec = document.getElementById('services');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  sec.insertBefore(canvas, sec.firstChild);

  const ctx = canvas.getContext('2d');
  function resize() {
    canvas.width = sec.clientWidth;
    canvas.height = sec.clientHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  let scrollRatio = 0;
  window.addEventListener('scroll', () => {
    const rect = sec.getBoundingClientRect();
    scrollRatio = Math.max(0, Math.min(1, 1 - rect.bottom / (window.innerHeight + sec.clientHeight)));
  });

  let t2 = 0;
  function draw() {
    requestAnimationFrame(draw);
    t2 += 0.015;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const spacing = 40;
    const cols = Math.ceil(canvas.width / spacing) + 1;
    const rows = Math.ceil(canvas.height / spacing) + 1;
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const x = c * spacing;
        const y = r * spacing;
        const wave = Math.sin(t2 + c * 0.3 + r * 0.2) * 0.5 + 0.5;
        const alpha = wave * 0.12;
        const size = 1 + wave * 1.5;
        ctx.beginPath();
        ctx.arc(x, y, size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(201,168,76,${alpha})`;
        ctx.fill();
      }
    }
    // Horizontal scan line
    const scanY = (t2 * 40) % (canvas.height + 60) - 30;
    const grad = ctx.createLinearGradient(0, scanY - 20, 0, scanY + 20);
    grad.addColorStop(0, 'transparent');
    grad.addColorStop(0.5, 'rgba(201,168,76,0.04)');
    grad.addColorStop(1, 'transparent');
    ctx.fillStyle = grad;
    ctx.fillRect(0, scanY - 20, canvas.width, 40);
  }
  draw();
})();

// ── WHY SECTION: Particle network canvas ──
(function() {
  const sec = document.getElementById('why');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  sec.style.position = 'relative';
  sec.insertBefore(canvas, sec.firstChild);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = sec.clientWidth; canvas.height = sec.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  const nodes = Array.from({ length: 60 }, () => ({
    x: Math.random() * 3000,
    y: Math.random() * 2000,
    vx: (Math.random() - 0.5) * 0.4,
    vy: (Math.random() - 0.5) * 0.4,
    r: Math.random() * 2 + 0.5,
  }));

  function drawNetwork() {
    requestAnimationFrame(drawNetwork);
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const scaleX = canvas.width / 3000;
    const scaleY = canvas.height / 2000;

    nodes.forEach(n => {
      n.x += n.vx; n.y += n.vy;
      if (n.x < 0 || n.x > 3000) n.vx *= -1;
      if (n.y < 0 || n.y > 2000) n.vy *= -1;
    });

    // Draw connections
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dx = nodes[i].x - nodes[j].x;
        const dy = nodes[i].y - nodes[j].y;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist < 400) {
          ctx.beginPath();
          ctx.strokeStyle = `rgba(201,168,76,${(1 - dist/400) * 0.08})`;
          ctx.lineWidth = 0.5;
          ctx.moveTo(nodes[i].x * scaleX, nodes[i].y * scaleY);
          ctx.lineTo(nodes[j].x * scaleX, nodes[j].y * scaleY);
          ctx.stroke();
        }
      }
    }

    // Draw nodes
    nodes.forEach(n => {
      ctx.beginPath();
      ctx.arc(n.x * scaleX, n.y * scaleY, n.r, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(201,168,76,0.2)';
      ctx.fill();
    });
  }
  drawNetwork();
})();

// ── PROCESS SECTION: Animated blueprint lines ──
(function() {
  const sec = document.getElementById('process');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  sec.style.position = 'relative';
  sec.insertBefore(canvas, sec.firstChild);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = sec.clientWidth; canvas.height = sec.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  let t3 = 0;
  function drawBlueprint() {
    requestAnimationFrame(drawBlueprint);
    t3 += 0.008;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Animated dashed arcs
    for (let i = 0; i < 4; i++) {
      const cx = canvas.width * (i + 1) / 5;
      const cy = canvas.height * 0.5;
      const r = 60 + i * 15;
      ctx.beginPath();
      ctx.arc(cx, cy, r, t3 + i, t3 + i + Math.PI * 1.2);
      ctx.strokeStyle = `rgba(201,168,76,${0.06 + i * 0.01})`;
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 8]);
      ctx.stroke();
      ctx.setLineDash([]);
    }

    // Crosshair marks at each step
    for (let i = 0; i < 5; i++) {
      const cx = canvas.width * (i + 1) / 6;
      const cy = canvas.height * 0.35;
      const pulse = (Math.sin(t3 * 2 + i * 1.2) + 1) * 0.5;
      ctx.strokeStyle = `rgba(214,96,49,${0.08 + pulse * 0.06})`;
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(cx - 15, cy); ctx.lineTo(cx + 15, cy); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(cx, cy - 15); ctx.lineTo(cx, cy + 15); ctx.stroke();
      // Circle
      ctx.beginPath();
      ctx.arc(cx, cy, 5 + pulse * 4, 0, Math.PI * 2);
      ctx.strokeStyle = `rgba(201,168,76,${0.1 + pulse * 0.08})`;
      ctx.stroke();
    }
  }
  drawBlueprint();
})();

// ── CONTACT SECTION: Glowing orb background ──
(function() {
  const sec = document.getElementById('contact');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  sec.insertBefore(canvas, sec.firstChild);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = sec.clientWidth; canvas.height = sec.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  let t4 = 0;
  function drawOrbs() {
    requestAnimationFrame(drawOrbs);
    t4 += 0.006;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const orbs = [
      { x: canvas.width * 0.15, y: canvas.height * 0.3, r: 200, col: '201,168,76' },
      { x: canvas.width * 0.85, y: canvas.height * 0.7, r: 160, col: '168,178,192' },
      { x: canvas.width * 0.5,  y: canvas.height * 0.1, r: 120, col: '214,96,49' },
    ];
    orbs.forEach((o, i) => {
      const pulse = 0.85 + Math.sin(t4 + i * 2) * 0.15;
      const r = o.r * pulse;
      const grad = ctx.createRadialGradient(o.x, o.y, 0, o.x, o.y, r);
      grad.addColorStop(0, `rgba(${o.col},0.06)`);
      grad.addColorStop(1, `rgba(${o.col},0)`);
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(o.x, o.y, r, 0, Math.PI * 2);
      ctx.fill();
    });
  }
  drawOrbs();
})();

// ── PORTFOLIO: Canvas sparkle on hover ──
document.querySelectorAll('.portfolio-item').forEach(item => {
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:4;';
  item.style.position = 'relative';
  item.appendChild(canvas);
  const ctx = canvas.getContext('2d');
  let sparks = [];
  let active = false;

  canvas.width = item.clientWidth || 400;
  canvas.height = item.clientHeight || 300;

  item.addEventListener('mouseenter', () => { active = true; spawnSparks(); });
  item.addEventListener('mouseleave', () => { active = false; });
  item.addEventListener('mousemove', e => {
    const r = item.getBoundingClientRect();
    for (let i = 0; i < 2; i++) {
      sparks.push({
        x: e.clientX - r.left, y: e.clientY - r.top,
        vx: (Math.random()-0.5)*3, vy: -Math.random()*3-1,
        life: 1, size: Math.random()*3+1
      });
    }
  });

  function spawnSparks() {
    if (!active) return;
    requestAnimationFrame(spawnSparks);
    canvas.width = item.clientWidth;
    canvas.height = item.clientHeight;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    sparks = sparks.filter(s => s.life > 0);
    sparks.forEach(s => {
      s.x += s.vx; s.y += s.vy; s.vy += 0.1; s.life -= 0.03;
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.size * s.life, 0, Math.PI*2);
      ctx.fillStyle = `rgba(201,168,76,${s.life * 0.8})`;
      ctx.fill();
    });
  }
});

// ── FOOTER: Animated star field ──
(function() {
  const footer = document.querySelector('footer');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;';
  footer.insertBefore(canvas, footer.firstChild);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = footer.clientWidth; canvas.height = footer.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  const stars = Array.from({length: 80}, () => ({
    x: Math.random(), y: Math.random(),
    r: Math.random() * 1.5,
    phase: Math.random() * Math.PI * 2,
    speed: 0.5 + Math.random()
  }));

  let t5 = 0;
  function drawStars() {
    requestAnimationFrame(drawStars);
    t5 += 0.01;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    stars.forEach(s => {
      const twinkle = (Math.sin(t5 * s.speed + s.phase) + 1) * 0.5;
      ctx.beginPath();
      ctx.arc(s.x * canvas.width, s.y * canvas.height, s.r * twinkle, 0, Math.PI*2);
      ctx.fillStyle = `rgba(201,168,76,${0.1 + twinkle * 0.25})`;
      ctx.fill();
    });
  }
  drawStars();
})();

// ── MAGNETIC BUTTONS ──
document.querySelectorAll('.btn-primary, .btn-outline, .btn-wa').forEach(btn => {
  btn.addEventListener('mousemove', e => {
    const r = btn.getBoundingClientRect();
    const dx = e.clientX - (r.left + r.width/2);
    const dy = e.clientY - (r.top + r.height/2);
    btn.style.transform = `translate(${dx*0.15}px, ${dy*0.15}px)`;
  });
  btn.addEventListener('mouseleave', () => {
    btn.style.transform = '';
  });
});

// ── SCROLL-TRIGGERED COUNTER with easing ──
function easeOutQuart(t) { return 1 - Math.pow(1-t, 4); }
document.querySelectorAll('[data-count]').forEach(el => {
  el._counted = false;
  const obs = new IntersectionObserver(entries => {
    if (entries[0].isIntersecting && !el._counted) {
      el._counted = true;
      const target = parseInt(el.getAttribute('data-count'));
      const dur = 2000;
      const start = performance.now();
      function update(now) {
        const p = Math.min((now - start) / dur, 1);
        el.textContent = Math.floor(easeOutQuart(p) * target) + '+';
        if (p < 1) requestAnimationFrame(update);
      }
      requestAnimationFrame(update);
    }
  }, { threshold: 0.5 });
  obs.observe(el);
});
</script>

