}
</style>

<!-- BLUEPRINT INTRO UNROLL -->
<div id="blueprint-overlay">
  <canvas id="bp-intro-canvas"></canvas>
</div>

<!-- RULER EDGES -->
<div class="ruler-top"><canvas id="ruler-h-canvas" height="18"></canvas></div>
