<!-- PENCIL SVG CURSOR -->
<svg id="pencil-icon" width="28" height="28" viewBox="0 0 24 24" fill="none">
  <path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25z" fill="rgba(201,168,76,0.9)"/>
  <path d="M20.71 7.04a1 1 0 000-1.41l-2.34-2.34a1 1 0 00-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z" fill="rgba(201,168,76,0.6)"/>
</svg>

<!-- COMPASS ROSE (fixed bottom-right) -->
<svg id="compass-rose" width="90" height="90" viewBox="0 0 100 100">
  <g stroke="#C9A84C" stroke-width="0.8" fill="none">
    <!-- Cardinal lines -->
    <line x1="50" y1="5" x2="50" y2="95"/>
    <line x1="5" y1="50" x2="95" y2="50"/>
    <line x1="15" y1="15" x2="85" y2="85"/>
    <line x1="85" y1="15" x2="15" y2="85"/>
    <!-- Concentric circles -->
    <circle cx="50" cy="50" r="40"/>
    <circle cx="50" cy="50" r="28"/>
    <circle cx="50" cy="50" r="14"/>
    <circle cx="50" cy="50" r="4"/>
    <!-- N arrow -->
    <polygon points="50,8 46,22 54,22" fill="rgba(201,168,76,0.8)" stroke="none"/>
    <!-- S arrow -->
    <polygon points="50,92 46,78 54,78" fill="rgba(168,178,192,0.5)" stroke="none"/>
    <!-- E arrow -->
