      <line x1="50" y1="10" x2="50" y2="14"/>
      <line x1="50" y1="86" x2="50" y2="90"/>
      <line x1="10" y1="50" x2="14" y2="50"/>
      <line x1="86" y1="50" x2="90" y2="50"/>
