<!-- FLOOR PLAN LIVE DRAW SECTION -->
<section id="floorplan-section">
  <div class="section-eyebrow reveal" style="position:relative;z-index:2">
    <span>Design Precision</span>
    <div class="eyebrow-line"></div>
  </div>
  <h2 class="section-title reveal" style="position:relative;z-index:2">
    Live <span class="gold">Blueprint</span> Studio
  </h2>
  <p class="section-desc reveal" style="position:relative;z-index:2;margin-bottom:0">Watch our architectural drafting process in real-time — every line drawn with precision.</p>
  <div id="fp-canvas-wrap">
    <canvas id="fp-main-canvas" height="420"></canvas>
  </div>
  <div id="fp-legend">
    <span class="l-gold">Structural Walls</span>
    <span class="l-silver">Interior Partitions</span>
    <span class="l-red">Load-Bearing Elements</span>
  </div>
</section>

<script>
// ══════════════════════════════════════════════════
// 1. BLUEPRINT INTRO UNROLL
// ══════════════════════════════════════════════════
(function() {
  const overlay = document.getElementById('blueprint-overlay');
  const canvas = document.getElementById('bp-intro-canvas');
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;

  // Draw blueprint grid on intro screen
  ctx.fillStyle = '#0a1628';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Fine grid
  ctx.strokeStyle = 'rgba(100,149,237,0.15)';
  ctx.lineWidth = 0.5;
  for (let x = 0; x < canvas.width; x += 20) {
    ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,canvas.height); ctx.stroke();
  }
  for (let y = 0; y < canvas.height; y += 20) {
    ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(canvas.width,y); ctx.stroke();
  }
  // Bold grid every 100px
  ctx.strokeStyle = 'rgba(100,149,237,0.3)';
  ctx.lineWidth = 1;
  for (let x = 0; x < canvas.width; x += 100) {
    ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,canvas.height); ctx.stroke();
  }
  for (let y = 0; y < canvas.height; y += 100) {
    ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(canvas.width,y); ctx.stroke();
  }

  // BEEN title in center
  ctx.fillStyle = 'rgba(201,168,76,0.9)';
  ctx.font = 'bold 64px Cinzel, serif';
  ctx.textAlign = 'center';
  ctx.fillText('BEEN', canvas.width/2, canvas.height/2 - 20);
  ctx.font = '14px Cinzel, serif';
  ctx.fillStyle = 'rgba(168,178,192,0.7)';
  ctx.letterSpacing = '6px';
  ctx.fillText('ARCHITECTURAL & ENGINEERING', canvas.width/2, canvas.height/2 + 20);

  // Crosshair center
  ctx.strokeStyle = 'rgba(214,96,49,0.6)';
  ctx.lineWidth = 1;
  ctx.setLineDash([4,6]);
  ctx.beginPath(); ctx.moveTo(canvas.width/2-60,canvas.height/2-50); ctx.lineTo(canvas.width/2+60,canvas.height/2-50); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(canvas.width/2,canvas.height/2-110); ctx.lineTo(canvas.width/2,canvas.height/2+30); ctx.stroke();
  ctx.setLineDash([]);

  setTimeout(() => { overlay.style.display = 'none'; }, 2200);
})();

// ══════════════════════════════════════════════════
// 2. RULER EDGES (top + left)
// ══════════════════════════════════════════════════
(function() {
  const hCanvas = document.getElementById('ruler-h-canvas');
  const vCanvas = document.getElementById('ruler-v-canvas');
  const hCtx = hCanvas.getContext('2d');
  const vCtx = vCanvas.getContext('2d');

  function drawRulers() {
    hCanvas.width = window.innerWidth;
    vCanvas.height = window.innerHeight;

    // Horizontal ruler
    hCtx.fillStyle = 'rgba(13,16,23,0.9)';
    hCtx.fillRect(0,0,hCanvas.width,18);
    for (let x = 0; x < hCanvas.width; x += 10) {
      const isMajor = x % 100 === 0;
      const isMid   = x % 50 === 0;
      const h = isMajor ? 10 : isMid ? 7 : 4;
      hCtx.strokeStyle = isMajor ? 'rgba(201,168,76,0.6)' : 'rgba(201,168,76,0.25)';
      hCtx.lineWidth = 0.8;
      hCtx.beginPath(); hCtx.moveTo(x,18); hCtx.lineTo(x,18-h); hCtx.stroke();
      if (isMajor && x > 0) {
        hCtx.fillStyle = 'rgba(201,168,76,0.4)';
        hCtx.font = '7px Inter, sans-serif';
        hCtx.fillText(x, x+2, 9);
      }
    }

    // Vertical ruler
    vCtx.fillStyle = 'rgba(13,16,23,0.9)';
    vCtx.fillRect(0,0,18,vCanvas.height);
    for (let y = 0; y < vCanvas.height; y += 10) {
      const isMajor = y % 100 === 0;
      const isMid   = y % 50 === 0;
      const w = isMajor ? 10 : isMid ? 7 : 4;
      vCtx.strokeStyle = isMajor ? 'rgba(201,168,76,0.6)' : 'rgba(201,168,76,0.25)';
      vCtx.lineWidth = 0.8;
      vCtx.beginPath(); vCtx.moveTo(18,y); vCtx.lineTo(18-w,y); vCtx.stroke();
      if (isMajor && y > 0) {
        vCtx.save();
        vCtx.translate(9, y);
        vCtx.rotate(-Math.PI/2);
        vCtx.fillStyle = 'rgba(201,168,76,0.4)';
        vCtx.font = '7px Inter, sans-serif';
        vCtx.fillText(y, -14, 3);
        vCtx.restore();
      }
    }
  }
  drawRulers();
  window.addEventListener('resize', drawRulers);
})();

// ══════════════════════════════════════════════════
// 3. PENCIL ICON follows cursor
// ══════════════════════════════════════════════════
(function() {
  const pencil = document.getElementById('pencil-icon');
  let px = -100, py = -100;
  document.addEventListener('mousemove', e => { px = e.clientX; py = e.clientY; });
  function movePencil() {
    pencil.style.left = px + 'px';
    pencil.style.top  = py + 'px';
    requestAnimationFrame(movePencil);
  }
  movePencil();
})();

// ══════════════════════════════════════════════════
// 4. PENCIL DRAWING TRAIL CANVAS
// ══════════════════════════════════════════════════
(function() {
  const canvas = document.getElementById('pencil-trail');
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  window.addEventListener('resize', () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; });

  let trail = [];
  let mx = 0, my = 0;
  document.addEventListener('mousemove', e => { mx = e.clientX; my = e.clientY; trail.push({x:mx,y:my,age:0}); });

  function drawTrail() {
    requestAnimationFrame(drawTrail);
    ctx.clearRect(0,0,canvas.width,canvas.height);
    trail = trail.filter(p => p.age < 60);
    trail.forEach(p => { p.age++; });
    if (trail.length < 2) return;
    for (let i = 1; i < trail.length; i++) {
      const a = trail[i-1], b = trail[i];
      const alpha = (1 - b.age/60) * 0.35;
      ctx.beginPath();
      ctx.moveTo(a.x, a.y);
      ctx.lineTo(b.x, b.y);
      ctx.strokeStyle = `rgba(201,168,76,${alpha})`;
      ctx.lineWidth = 1.2;
      ctx.lineCap = 'round';
      ctx.stroke();
    }
  }
  drawTrail();
})();

// ══════════════════════════════════════════════════
// 5. GLOBAL COMPASS ARCS (follows mouse, draws arcs)
// ══════════════════════════════════════════════════
(function() {
  const canvas = document.getElementById('arch-compass-canvas');
  const ctx = canvas.getContext('2d');
  function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
  resize();
  window.addEventListener('resize', resize);

  let mx = window.innerWidth/2, my = window.innerHeight/2;
  let compassArcs = [];
  let clickArcs = [];

  document.addEventListener('mousemove', e => { mx = e.clientX; my = e.clientY; });

  // On click: spawn a compass-drawn arc animation
  document.addEventListener('click', e => {
    if (e.target.tagName === 'A' || e.target.tagName === 'BUTTON' || e.target.closest('a') || e.target.closest('button')) return;
    clickArcs.push({ x: e.clientX, y: e.clientY, r: 0, maxR: 80 + Math.random()*60, angle: Math.random()*Math.PI*2, life: 1 });
  });

  let t = 0;
  function draw() {
    requestAnimationFrame(draw);
    t += 0.012;
    ctx.clearRect(0,0,canvas.width,canvas.height);

    // Subtle compass arcs emanating from cursor
    for (let i = 0; i < 3; i++) {
      const r = 30 + i*25 + Math.sin(t + i) * 8;
      const startAngle = t * (0.3 + i*0.1);
      const arcLen = Math.PI * 0.6;
      ctx.beginPath();
      ctx.arc(mx, my, r, startAngle, startAngle + arcLen);
      ctx.strokeStyle = `rgba(201,168,76,${0.06 - i*0.015})`;
      ctx.lineWidth = 1;
      ctx.setLineDash([3, 5]);
      ctx.stroke();
      ctx.setLineDash([]);

      // Endpoint dot
      const ex = mx + Math.cos(startAngle + arcLen) * r;
      const ey = my + Math.sin(startAngle + arcLen) * r;
      ctx.beginPath();
      ctx.arc(ex, ey, 2, 0, Math.PI*2);
      ctx.fillStyle = `rgba(201,168,76,0.2)`;
      ctx.fill();
    }

    // Compass needle lines from cursor
    for (let i = 0; i < 2; i++) {
      const angle = t * 0.2 + i * Math.PI;
      const len = 50 + i * 20;
      ctx.beginPath();
      ctx.moveTo(mx, my);
      ctx.lineTo(mx + Math.cos(angle)*len, my + Math.sin(angle)*len);
      ctx.strokeStyle = `rgba(168,178,192,0.05)`;
      ctx.lineWidth = 0.8;
      ctx.stroke();
    }

    // Click arc animations
    clickArcs = clickArcs.filter(a => a.life > 0);
    clickArcs.forEach(a => {
      a.r += (a.maxR - a.r) * 0.06;
      a.life -= 0.018;
      ctx.beginPath();
      ctx.arc(a.x, a.y, a.r, a.angle, a.angle + Math.PI * 1.5);
      ctx.strokeStyle = `rgba(201,168,76,${a.life * 0.5})`;
      ctx.lineWidth = 1.5;
      ctx.setLineDash([4,6]);
      ctx.stroke();
      ctx.setLineDash([]);

      // Center dot
      ctx.beginPath();
      ctx.arc(a.x, a.y, Math.max(0, 3 * a.life), 0, Math.PI*2);
      ctx.fillStyle = `rgba(214,96,49,${a.life * 0.6})`;
      ctx.fill();

      // Dimension arrow-heads
      const ex = a.x + Math.cos(a.angle) * a.r;
      const ey = a.y + Math.sin(a.angle) * a.r;
      ctx.beginPath();
      ctx.arc(ex, ey, 3, 0, Math.PI*2);
      ctx.fillStyle = `rgba(201,168,76,${a.life * 0.7})`;
      ctx.fill();
    });
  }
  draw();
})();

// ══════════════════════════════════════════════════
// 6. LIVE FLOOR PLAN DRAW (the dedicated section)
// ══════════════════════════════════════════════════
(function() {
  const canvas = document.getElementById('fp-main-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');

  function resize() {
    canvas.width = canvas.parentElement.clientWidth;
  }
  resize();
  window.addEventListener('resize', () => { resize(); resetPlan(); });

  const GOLD = 'rgba(201,168,76,';
  const SILVER = 'rgba(168,178,192,';
  const RED = 'rgba(214,96,49,';
  const BLUE = 'rgba(100,149,237,';

  // Floor plan room definitions (normalized 0-1 coords)
  const rooms = [
    { label: 'LIVING ROOM',      x:0.05, y:0.08, w:0.35, h:0.45, type:'main' },
    { label: 'MASTER BEDROOM',   x:0.42, y:0.08, w:0.30, h:0.38, type:'main' },
    { label: 'BEDROOM 2',        x:0.74, y:0.08, w:0.21, h:0.28, type:'main' },
    { label: 'KITCHEN',          x:0.05, y:0.55, w:0.20, h:0.30, type:'secondary' },
    { label: 'DINING',           x:0.27, y:0.55, w:0.18, h:0.30, type:'secondary' },
    { label: 'BATH 1',           x:0.47, y:0.48, w:0.12, h:0.18, type:'service' },
    { label: 'BATH 2',           x:0.74, y:0.38, w:0.12, h:0.20, type:'service' },
    { label: 'CORRIDOR',         x:0.47, y:0.68, w:0.48, h:0.12, type:'corridor' },
    { label: 'BALCONY',          x:0.62, y:0.08, w:0.10, h:0.10, type:'outdoor' },
    { label: 'UTILITY',          x:0.62, y:0.68, w:0.12, h:0.18, type:'service' },
  ];

  // Doors and windows
  const doors = [
    { room:0, side:'right', pos:0.6, w:0.12 },
    { room:1, side:'left',  pos:0.7, w:0.1 },
    { room:2, side:'bottom',pos:0.5, w:0.1 },
    { room:3, side:'right', pos:0.5, w:0.1 },
    { room:4, side:'left',  pos:0.5, w:0.1 },
  ];

  let drawProgress = []; // per-room progress 0→1
  let dimProgress = 0;
  let annotProgress = 0;
  rooms.forEach(() => drawProgress.push(0));

  function resetPlan() {
    drawProgress = drawProgress.map(() => 0);
    dimProgress = 0; annotProgress = 0;
  }

  // Animate drawing
  let drawing = false;
  const fpObs = new IntersectionObserver(entries => {
    if (entries[0].isIntersecting && !drawing) {
      drawing = true;
      animatePlan();
    }
  }, { threshold: 0.3 });
  fpObs.observe(canvas);

  let t = 0;
  function animatePlan() {
    requestAnimationFrame(animatePlan);
    t += 0.008;

    const W = canvas.width, H = canvas.height;
    ctx.clearRect(0, 0, W, H);

    // Background grid
    ctx.strokeStyle = 'rgba(100,149,237,0.06)';
    ctx.lineWidth = 0.5;
    const gs = 20;
    for (let x = 0; x < W; x += gs) { ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke(); }
    for (let y = 0; y < H; y += gs) { ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); }
    // Bold every 100px
    ctx.strokeStyle = 'rgba(100,149,237,0.12)';
    for (let x = 0; x < W; x += 100) { ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke(); }
    for (let y = 0; y < H; y += 100) { ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); }

    // Advance progress
    rooms.forEach((_, i) => {
      const delay = i * 0.12;
      if (t > delay) drawProgress[i] = Math.min(1, drawProgress[i] + 0.015);
    });
    if (t > rooms.length * 0.12 + 0.3) dimProgress = Math.min(1, dimProgress + 0.012);
    if (t > rooms.length * 0.12 + 0.8) annotProgress = Math.min(1, annotProgress + 0.015);

    // Draw each room
    rooms.forEach((room, i) => {
      const p = drawProgress[i];
      if (p <= 0) return;
      const x = room.x * W, y = room.y * H, w = room.w * W, h = room.h * H;

      // Wall color by type
      const wallColor = room.type === 'main' ? `${GOLD}${0.7*p})` :
                        room.type === 'service' ? `${RED}${0.5*p})` :
                        room.type === 'corridor' ? `${SILVER}${0.4*p})` :
                        room.type === 'outdoor' ? 'rgba(100,200,100,' + 0.4*p + ')' :
                        `${SILVER}${0.55*p})`;

      // Room fill
      ctx.fillStyle = room.type === 'main' ? `rgba(201,168,76,${0.03*p})` :
                      room.type === 'service' ? `rgba(214,96,49,${0.03*p})` :
                      `rgba(100,149,237,${0.02*p})`;
      ctx.fillRect(x, y, w*p, h);

      // Animated wall draw (perimeter)
      const perimeter = 2*(w+h);
      const drawn = perimeter * p;
      ctx.strokeStyle = wallColor;
      ctx.lineWidth = room.type === 'main' ? 2.5 : 1.5;
      ctx.setLineDash([]);

      // Draw walls progressively around the rectangle
      let rem = drawn;
      ctx.beginPath();
      ctx.moveTo(x, y);
      // Top
      if (rem > 0) { const seg = Math.min(rem, w); ctx.lineTo(x+seg, y); rem -= seg; }
      // Right
      if (rem > 0) { const seg = Math.min(rem, h); ctx.lineTo(x+w, y+seg); rem -= seg; }
      // Bottom
      if (rem > 0) { const seg = Math.min(rem, w); ctx.lineTo(x+w-seg, y+h); rem -= seg; }
      // Left
      if (rem > 0) { const seg = Math.min(rem, h); ctx.lineTo(x, y+h-seg); rem -= seg; }
      ctx.stroke();

      // Label (appears when room fully drawn)
      if (p > 0.95) {
        ctx.fillStyle = `rgba(201,168,76,${(p-0.95)*20 * (room.type==='main' ? 0.8 : 0.5)})`;
        ctx.font = `${Math.max(7, Math.min(10, w/room.label.length * 1.5))}px Cinzel, monospace`;
        ctx.textAlign = 'center';
        ctx.fillText(room.label, x + w/2, y + h/2);

        // Area measurement
        const areaSqft = Math.round(room.w * 50 * room.h * 35);
        ctx.fillStyle = `rgba(168,178,192,0.35)`;
        ctx.font = '8px Inter, monospace';
        ctx.fillText(areaSqft + ' sq.ft', x + w/2, y + h/2 + 13);
      }
    });

    // Dimension lines
    if (dimProgress > 0) {
      ctx.strokeStyle = `rgba(214,96,49,${dimProgress * 0.6})`;
      ctx.fillStyle = `rgba(214,96,49,${dimProgress * 0.7})`;
      ctx.lineWidth = 0.8;
      ctx.setLineDash([3,4]);
      ctx.font = '8px Inter, monospace';
      ctx.textAlign = 'center';

      // Overall width dimension
      const oy = H * 0.92;
      ctx.beginPath(); ctx.moveTo(W*0.05, oy); ctx.lineTo(W*0.95*dimProgress + W*0.05*(1-dimProgress), oy); ctx.stroke();
      // Arrowheads
      if (dimProgress > 0.8) {
        ctx.setLineDash([]);
        const aw = 6;
        ctx.beginPath(); ctx.moveTo(W*0.05, oy); ctx.lineTo(W*0.05+aw, oy-3); ctx.lineTo(W*0.05+aw, oy+3); ctx.closePath(); ctx.fill();
        ctx.beginPath(); ctx.moveTo(W*0.95, oy); ctx.lineTo(W*0.95-aw, oy-3); ctx.lineTo(W*0.95-aw, oy+3); ctx.closePath(); ctx.fill();
        ctx.fillText('18.5 m', W*0.5, oy-5);
      }
      ctx.setLineDash([]);
    }

    // Drawing tool indicator (pencil tip animation)
    if (t < rooms.length * 0.12 + 0.5) {
      const roomIdx = Math.min(Math.floor(t / 0.12), rooms.length-1);
      const room = rooms[roomIdx];
      const progress = drawProgress[roomIdx];
      const x = room.x * W, y = room.y * H, w = room.w * W, h = room.h * H;
      const perimeter = 2*(w+h);
      const drawn = perimeter * progress;

      // Find current drawing tip position
      let tipX = x, tipY = y;
      let rem2 = drawn;
      if (rem2 > 0) { const seg = Math.min(rem2, w); tipX = x + seg; tipY = y; rem2 -= seg; }
      if (rem2 > 0) { const seg = Math.min(rem2, h); tipX = x + w; tipY = y + seg; rem2 -= seg; }
      if (rem2 > 0) { const seg = Math.min(rem2, w); tipX = x + w - seg; tipY = y + h; rem2 -= seg; }
      if (rem2 > 0) { const seg = Math.min(rem2, h); tipX = x; tipY = y + h - seg; }

      // Glowing pencil tip
      const glow = ctx.createRadialGradient(tipX, tipY, 0, tipX, tipY, 12);
      glow.addColorStop(0, 'rgba(201,168,76,0.8)');
      glow.addColorStop(0.4, 'rgba(201,168,76,0.3)');
      glow.addColorStop(1, 'transparent');
      ctx.fillStyle = glow;
      ctx.beginPath(); ctx.arc(tipX, tipY, 12, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(tipX, tipY, 3, 0, Math.PI*2);
      ctx.fillStyle = '#C9A84C'; ctx.fill();
    }

    // Annotations
    if (annotProgress > 0) {
      ctx.fillStyle = `rgba(168,178,192,${annotProgress * 0.5})`;
      ctx.font = '8px Inter, monospace';
      ctx.textAlign = 'left';
      ctx.fillText('GROUND FLOOR PLAN', W * 0.05, H * 0.97);
      ctx.textAlign = 'right';
      ctx.fillText('SCALE 1:100', W * 0.95, H * 0.97);
      ctx.fillStyle = `rgba(201,168,76,${annotProgress * 0.4})`;
      ctx.fillText('BEEN ARCHITECTURAL & ENGINEERING', W * 0.95, H * 0.97 - 12);
    }
  }
})();

// ══════════════════════════════════════════════════
// 7. T-SQUARE on Services Section
// ══════════════════════════════════════════════════
(function() {
  const sec = document.getElementById('services');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:2;';
  sec.appendChild(canvas);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = sec.clientWidth; canvas.height = sec.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  let scrollY = 0;
  window.addEventListener('scroll', () => { scrollY = window.scrollY; });

  function drawTSquare() {
    requestAnimationFrame(drawTSquare);
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const rect = sec.getBoundingClientRect();
    const relScroll = -rect.top;
    const progress = Math.max(0, Math.min(1, relScroll / (sec.clientHeight * 0.6)));

    // T-Square horizontal blade — slides across
    const bladeY = canvas.height * 0.15 + progress * canvas.height * 0.3;
    const bladeLen = canvas.width * progress;

    // Blade
    ctx.strokeStyle = 'rgba(201,168,76,0.12)';
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(0, bladeY); ctx.lineTo(bladeLen, bladeY); ctx.stroke();

    // Head (vertical part)
    ctx.strokeStyle = 'rgba(201,168,76,0.18)';
    ctx.lineWidth = 4;
    ctx.beginPath(); ctx.moveTo(8, bladeY - 30); ctx.lineTo(8, bladeY + 30); ctx.stroke();

    // Graduation marks along blade
    ctx.strokeStyle = 'rgba(201,168,76,0.2)';
    ctx.lineWidth = 0.8;
    for (let x = 0; x < bladeLen; x += 20) {
      const h = x % 100 === 0 ? 10 : x % 50 === 0 ? 7 : 4;
      ctx.beginPath(); ctx.moveTo(x, bladeY); ctx.lineTo(x, bladeY - h); ctx.stroke();
    }

    // Set-square triangle (45°) sliding with blade
    if (progress > 0.3) {
      const tx = bladeLen * 0.6;
      const ty = bladeY;
      const size = 60 * (progress - 0.3) / 0.7;
      ctx.strokeStyle = 'rgba(168,178,192,0.12)';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(tx, ty);
      ctx.lineTo(tx + size, ty);
      ctx.lineTo(tx, ty - size);
      ctx.closePath();
      ctx.stroke();
      // Right-angle marker
      ctx.beginPath();
      ctx.moveTo(tx + 10, ty);
      ctx.lineTo(tx + 10, ty - 10);
      ctx.lineTo(tx, ty - 10);
      ctx.strokeStyle = 'rgba(214,96,49,0.15)';
      ctx.stroke();
    }

    // Second T-square lower
    const bladeY2 = canvas.height * 0.75 - progress * canvas.height * 0.15;
    const bladeLen2 = canvas.width * (1 - progress * 0.2);
    ctx.strokeStyle = 'rgba(168,178,192,0.06)';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(canvas.width - bladeLen2 * 0.4, bladeY2); ctx.lineTo(canvas.width, bladeY2); ctx.stroke();
  }
  drawTSquare();
})();

// ══════════════════════════════════════════════════
// 8. DRAWING COMPASS (Why section) — Three.js version
// ══════════════════════════════════════════════════
(function() {
  const sec = document.getElementById('why');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:1;';
  sec.appendChild(canvas);
  const ctx = canvas.getContext('2d');

  function resize() { canvas.width = sec.clientWidth; canvas.height = sec.clientHeight; }
  resize();
  window.addEventListener('resize', resize);

  // Compass objects — each draws arcs
  const compasses = [
    { cx: 0.85, cy: 0.2, r: 80, speed: 0.3, color: 'rgba(201,168,76,', arm: 0 },
    { cx: 0.12, cy: 0.8, r: 120, speed: -0.2, color: 'rgba(168,178,192,', arm: 1 },
    { cx: 0.5,  cy: 0.5, r: 60,  speed: 0.5, color: 'rgba(214,96,49,', arm: 0.5 },
  ];

  let t = 0;
  function draw() {
    requestAnimationFrame(draw);
    t += 0.006;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    compasses.forEach(c => {
      const cx = c.cx * canvas.width;
      const cy = c.cy * canvas.height;
      const angle = t * c.speed + c.arm * Math.PI;

      // Drawn arc history
      ctx.beginPath();
      ctx.arc(cx, cy, c.r, 0, Math.PI * 2);
      ctx.strokeStyle = c.color + '0.05)';
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 8]);
      ctx.stroke();
      ctx.setLineDash([]);

      // Compass needle arm
      const ex = cx + Math.cos(angle) * c.r;
      const ey = cy + Math.sin(angle) * c.r;

      // Arm line
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.lineTo(ex, ey);
      ctx.strokeStyle = c.color + '0.15)';
      ctx.lineWidth = 1.2;
      ctx.stroke();

      // Second arm (compass has 2 legs)
      const ang2 = angle + 0.3;
      const ex2 = cx + Math.cos(ang2) * c.r;
      const ey2 = cy + Math.sin(ang2) * c.r;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.lineTo(ex2, ey2);
      ctx.strokeStyle = c.color + '0.1)';
      ctx.lineWidth = 1;
      ctx.stroke();

      // Pivot point
      ctx.beginPath(); ctx.arc(cx, cy, 3, 0, Math.PI*2);
      ctx.fillStyle = c.color + '0.4)'; ctx.fill();

      // Pencil tip (needle point)
      ctx.beginPath(); ctx.arc(ex, ey, 2.5, 0, Math.PI*2);
      ctx.fillStyle = c.color + '0.6)'; ctx.fill();

      // Drawn partial arc (recent sweep)
      ctx.beginPath();
      ctx.arc(cx, cy, c.r, angle - 0.8, angle);
      ctx.strokeStyle = c.color + '0.18)';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    });
  }
  draw();
})();

// ══════════════════════════════════════════════════
// 9. PROTRACTORS on About section
// ══════════════════════════════════════════════════
(function() {
  const sec = document.getElementById('about');
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;top:0;right:0;width:300px;height:300px;pointer-events:none;z-index:1;opacity:0.08;';
  sec.appendChild(canvas);
  const ctx = canvas.getContext('2d');
  canvas.width = 300; canvas.height = 300;

  const cx = 250, cy = 50, r = 200;
  // Semicircle protractor
  ctx.strokeStyle = '#C9A84C';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.arc(cx, cy, r, Math.PI, Math.PI*2);
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(cx - r, cy); ctx.lineTo(cx + r, cy); ctx.stroke();

  // Degree marks
  for (let deg = 0; deg <= 180; deg += 10) {
    const rad = (deg + 180) * Math.PI / 180;
    const inner = deg % 30 === 0 ? r - 16 : deg % 10 === 0 ? r - 10 : r - 6;
    ctx.beginPath();
    ctx.moveTo(cx + Math.cos(rad)*r, cy + Math.sin(rad)*r);
    ctx.lineTo(cx + Math.cos(rad)*inner, cy + Math.sin(rad)*inner);
    ctx.stroke();
    if (deg % 30 === 0) {
      ctx.fillStyle = '#C9A84C';
      ctx.font = '10px Inter';
      ctx.textAlign = 'center';
      ctx.fillText(deg + '°', cx + Math.cos(rad)*(r-26), cy + Math.sin(rad)*(r-26) + 3);
    }
  }
})();

// ══════════════════════════════════════════════════
// 10. FLOATING ARCH TOOL ICONS (spawn periodically)
// ══════════════════════════════════════════════════
(function() {
  const tools = [
    // Pencil SVG
    `<svg width="24" height="24" viewBox="0 0 24 24" fill="rgba(201,168,76,0.8)"><path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25zm2.92 1.42L14.06 10.5l.44.44-8.14 8.14-.44-.44zM20.71 7.04a1 1 0 000-1.41l-2.34-2.34a1 1 0 00-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z"/></svg>`,
    // Ruler
    `<svg width="28" height="12" viewBox="0 0 56 24" fill="none" stroke="rgba(201,168,76,0.8)" stroke-width="1.5"><rect x="1" y="1" width="54" height="22" rx="2"/><line x1="8" y1="1" x2="8" y2="10"/><line x1="16" y1="1" x2="16" y2="7"/><line x1="24" y1="1" x2="24" y2="10"/><line x1="32" y1="1" x2="32" y2="7"/><line x1="40" y1="1" x2="40" y2="10"/><line x1="48" y1="1" x2="48" y2="7"/></svg>`,
    // Triangle set square
    `<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="rgba(168,178,192,0.8)" stroke-width="1.5"><path d="M3 21L21 21L3 3Z"/><line x1="3" y1="21" x2="3" y2="15"/></svg>`,
    // Compass
    `<svg width="20" height="24" viewBox="0 0 20 28" fill="none" stroke="rgba(201,168,76,0.8)" stroke-width="1.5"><line x1="10" y1="8" x2="3" y2="26"/><line x1="10" y1="8" x2="17" y2="26"/><circle cx="10" cy="5" r="4"/><line x1="10" y1="9" x2="10" y2="13"/></svg>`,
    // Protractor arc
    `<svg width="28" height="16" viewBox="0 0 56 30" fill="none" stroke="rgba(214,96,49,0.7)" stroke-width="1.5"><path d="M4 28 A24 24 0 0 1 52 28"/><line x1="4" y1="28" x2="52" y2="28"/></svg>`,
  ];

  function spawnTool() {
    const el = document.createElement('div');
    el.className = 'arch-tool-float';
    el.innerHTML = tools[Math.floor(Math.random() * tools.length)];
    el.style.left = (10 + Math.random() * 80) + '%';
    el.style.top  = (20 + Math.random() * 60) + '%';
    const dur = 4 + Math.random() * 4;
    el.style.animationDuration = dur + 's';
    el.style.animationDelay = '0s';
    document.body.appendChild(el);
    setTimeout(() => el.remove(), dur * 1000);
  }

  // Spawn tools periodically
  setInterval(spawnTool, 2800);
  setTimeout(spawnTool, 1000);
  setTimeout(spawnTool, 2000);
})();

// ══════════════════════════════════════════════════
// 11. DIMENSION LINES on service cards (hover)
// ══════════════════════════════════════════════════
document.querySelectorAll('.service-card').forEach(card => {
  const canvas = document.createElement('canvas');
  canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:5;';
  card.style.position = 'relative';
  card.appendChild(canvas);
  const ctx = canvas.getContext('2d');
  let active = false, progress = 0;

  card.addEventListener('mouseenter', () => { active = true; });
  card.addEventListener('mouseleave', () => { active = false; });

  function draw() {
    requestAnimationFrame(draw);
    canvas.width = card.clientWidth; canvas.height = card.clientHeight;
    progress += active ? 0.06 : -0.06;
    progress = Math.max(0, Math.min(1, progress));
    if (progress === 0) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const p = progress;
    const W = canvas.width, H = canvas.height;
    const pad = 10;
    ctx.strokeStyle = `rgba(201,168,76,${p * 0.5})`;
    ctx.lineWidth = 0.8;
    ctx.setLineDash([3,5]);

    // Top dimension line
    ctx.beginPath(); ctx.moveTo(pad, pad); ctx.lineTo(W * p - pad + pad, pad); ctx.stroke();
    // Left dimension line
    ctx.beginPath(); ctx.moveTo(pad, pad); ctx.lineTo(pad, H * p - pad + pad); ctx.stroke();

    // Arrow heads
    if (p > 0.7) {
      ctx.fillStyle = `rgba(214,96,49,${p * 0.6})`;
      ctx.setLineDash([]);
      // Top-right arrowhead
      ctx.beginPath(); ctx.moveTo(W-pad,pad); ctx.lineTo(W-pad-8,pad-3); ctx.lineTo(W-pad-8,pad+3); ctx.closePath(); ctx.fill();
      // Bottom-left arrowhead
      ctx.beginPath(); ctx.moveTo(pad,H-pad); ctx.lineTo(pad-3,H-pad-8); ctx.lineTo(pad+3,H-pad-8); ctx.closePath(); ctx.fill();
      ctx.setLineDash([3,5]);
      // Right line
      ctx.strokeStyle = `rgba(201,168,76,${p * 0.3})`;
      ctx.beginPath(); ctx.moveTo(W-pad, pad); ctx.lineTo(W-pad, H-pad); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(pad, H-pad); ctx.lineTo(W-pad, H-pad); ctx.stroke();
      // Measurement text
      ctx.fillStyle = `rgba(201,168,76,${p * 0.5})`;
      ctx.font = '7px monospace';
      ctx.textAlign = 'center';
      ctx.fillText('3.2m × 4.8m', W/2, H - pad - 5);
    }
    ctx.setLineDash([]);
  }
  draw();
});
</script>
